sql:
SELECT precinct_name, SUM(registered_voters_total) AS total_registered_voters
FROM precincts
GROUP BY precinct_name;

external_knowledge:
'sailing under the banner' refers to candidates participating in a race;
'electoral sea' is a metaphor for the election date;
'ships' metaphorically represents the candidates;
'oceans they've traversed' refers to the precinct name;
'waves they've ridden' represents the total votes;
'wave count' refers to the number of votes in each count.

sql:
SELECT COUNT(DISTINCT voter_id) AS unique_voters
FROM voter_history
WHERE election_date = '2022-11-08';

SELECT AVG(election_results.turnout_percentage) AS average_turnout_percentage
FROM precincts
JOIN election_results ON precincts.precinct_code = election_results.precinct_code;
